import{_ as t,o as a,c as o,a3 as s}from"./chunks/framework.SVq0s9jj.js";const p=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),i={name:"guide/faq.md"};function n(r,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Common questions about Specialist Agent.</p><div class="tip custom-block"><p class="custom-block-title">Can&#39;t find your answer?</p><p>Open an issue on <a href="https://github.com/HerbertJulio/specialist-agent/issues" target="_blank" rel="noreferrer">GitHub</a> - we&#39;re happy to help.</p></div><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><h3 id="can-i-use-it-without-a-framework-pack" tabindex="-1">Can I use it without a framework pack? <a class="header-anchor" href="#can-i-use-it-without-a-framework-pack" aria-label="Permalink to &quot;Can I use it without a framework pack?&quot;">​</a></h3><p>Yes. The 9 framework-agnostic agents (<code>@starter</code>, <code>@explorer</code>, <code>@finance</code>, <code>@cloud</code>, <code>@security</code>, <code>@designer</code>, <code>@data</code>, <code>@devops</code>, <code>@tester</code>) work independently of any pack. They don&#39;t require <code>ARCHITECTURE.md</code> or pack-specific files.</p><p>The pack-specific agents (<code>@builder</code>, <code>@reviewer</code>, <code>@doctor</code>, <code>@migrator</code>) require a framework pack because they rely on <code>ARCHITECTURE.md</code> for code generation patterns.</p><h3 id="does-it-work-with-existing-projects" tabindex="-1">Does it work with existing projects? <a class="header-anchor" href="#does-it-work-with-existing-projects" aria-label="Permalink to &quot;Does it work with existing projects?&quot;">​</a></h3><p>Yes. Run <code>npx specialist-agent init</code> in your project root and choose your framework pack. The installer only adds markdown files - it doesn&#39;t modify your source code, dependencies, or configuration.</p><p>Use <code>@explorer</code> to assess an existing codebase before making changes:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Use @explorer to assess this project&#39;s architecture and health&quot;</span></span></code></pre></div><h3 id="how-does-it-work-with-monorepos" tabindex="-1">How does it work with monorepos? <a class="header-anchor" href="#how-does-it-work-with-monorepos" aria-label="Permalink to &quot;How does it work with monorepos?&quot;">​</a></h3><p>Each workspace can have its own <code>ARCHITECTURE.md</code> and <code>CLAUDE.md</code>. When you open Claude Code in a specific workspace directory, agents read that workspace&#39;s configuration.</p><p>For shared patterns across workspaces, keep a root-level <code>ARCHITECTURE.md</code> with common rules, and workspace-level files for overrides.</p><h3 id="does-it-work-offline" tabindex="-1">Does it work offline? <a class="header-anchor" href="#does-it-work-offline" aria-label="Permalink to &quot;Does it work offline?&quot;">​</a></h3><p>No. Specialist Agent requires an active connection to the Claude API. The agents and skills are markdown instructions that Claude Code reads and executes - the intelligence comes from the Claude model, not from local code.</p><h3 id="how-do-i-update-specialist-agent" tabindex="-1">How do I update Specialist Agent? <a class="header-anchor" href="#how-do-i-update-specialist-agent" aria-label="Permalink to &quot;How do I update Specialist Agent?&quot;">​</a></h3><p>Run the installer again:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> specialist-agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>It overwrites the agent and skill files with the latest versions. Your <code>ARCHITECTURE.md</code> customizations are preserved since they live in a separate file.</p><h2 id="agents" tabindex="-1">Agents <a class="header-anchor" href="#agents" aria-label="Permalink to &quot;Agents&quot;">​</a></h2><h3 id="what-s-the-difference-between-full-and-lite-agents" tabindex="-1">What&#39;s the difference between Full and Lite agents? <a class="header-anchor" href="#what-s-the-difference-between-full-and-lite-agents" aria-label="Permalink to &quot;What&#39;s the difference between Full and Lite agents?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Full Agents</th><th>Lite Agents</th></tr></thead><tbody><tr><td>Model</td><td>Sonnet/Opus</td><td>Haiku</td></tr><tr><td>Cost</td><td>Higher per token</td><td>~50% cheaper</td></tr><tr><td>Quality</td><td>Better for complex tasks</td><td>Good for simple tasks</td></tr><tr><td>Speed</td><td>Slower</td><td>Faster</td></tr><tr><td>Best for</td><td>New modules, PR reviews, migrations</td><td>Prototyping, simple scaffolds, iteration</td></tr></tbody></table><p>Use Lite agents when speed matters more than polish. Use Full agents when accuracy is critical (PR reviews, migrations, bug investigations).</p><h3 id="can-i-create-my-own-agents" tabindex="-1">Can I create my own agents? <a class="header-anchor" href="#can-i-create-my-own-agents" aria-label="Permalink to &quot;Can I create my own agents?&quot;">​</a></h3><p>Yes. See <a href="/pr-preview/pr-65/customization/creating-agents.html">Creating Agents</a> for a step-by-step guide. Custom agents follow the same 5-part blueprint:</p><ol><li><strong>Mission</strong> - What the agent does</li><li><strong>Workflow</strong> - Step-by-step process</li><li><strong>Output</strong> - Structured result format</li><li><strong>Rules</strong> - Hard constraints</li><li><strong>Handoff Protocol</strong> - When to suggest other agents</li></ol><h3 id="how-do-agents-know-my-project-s-conventions" tabindex="-1">How do agents know my project&#39;s conventions? <a class="header-anchor" href="#how-do-agents-know-my-project-s-conventions" aria-label="Permalink to &quot;How do agents know my project&#39;s conventions?&quot;">​</a></h3><p>All agents read <code>docs/ARCHITECTURE.md</code> before acting. This file defines your naming conventions, directory structure, layer rules, and code patterns. When you edit it, every agent&#39;s behavior changes immediately.</p><h3 id="can-i-use-agents-from-different-packs" tabindex="-1">Can I use agents from different packs? <a class="header-anchor" href="#can-i-use-agents-from-different-packs" aria-label="Permalink to &quot;Can I use agents from different packs?&quot;">​</a></h3><p>Each project should use one framework pack. The pack-specific agents (<code>@builder</code>, <code>@reviewer</code>, <code>@doctor</code>, <code>@migrator</code>) are tailored to a specific framework&#39;s patterns. Using React agents in a Vue project would generate incorrect code.</p><p>The framework-agnostic agents work with any pack.</p><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><h3 id="how-much-does-it-cost-to-use" tabindex="-1">How much does it cost to use? <a class="header-anchor" href="#how-much-does-it-cost-to-use" aria-label="Permalink to &quot;How much does it cost to use?&quot;">​</a></h3><p>Costs depend on the Claude model and number of tokens consumed. See <a href="/pr-preview/pr-65/reference/tokens.html">Token Usage</a> for detailed estimates per operation, including real-world scenarios.</p><p><strong>Quick reference:</strong></p><ul><li>Single component scaffold: ~3-5k tokens</li><li>Full module with tests: ~40-60k tokens</li><li>Module migration: ~50-120k tokens</li></ul><h3 id="how-can-i-reduce-costs" tabindex="-1">How can I reduce costs? <a class="header-anchor" href="#how-can-i-reduce-costs" aria-label="Permalink to &quot;How can I reduce costs?&quot;">​</a></h3><ol><li>Use <strong>Lite agents</strong> for rapid iteration</li><li>Use <strong>skills</strong> instead of agents for focused tasks (cheaper)</li><li>Migrate <strong>incrementally</strong> (one component at a time)</li><li>Run automated checks before full reviews</li></ol><p>See <a href="/pr-preview/pr-65/reference/tokens.html#tips-to-reduce-token-usage">Tips to Reduce Token Usage</a> for more strategies.</p><h2 id="strategy-workflow" tabindex="-1">Strategy &amp; Workflow <a class="header-anchor" href="#strategy-workflow" aria-label="Permalink to &quot;Strategy &amp; Workflow&quot;">​</a></h2><h3 id="when-should-i-use-a-command-vs-agent-vs-skill" tabindex="-1">When should I use a command vs agent vs skill? <a class="header-anchor" href="#when-should-i-use-a-command-vs-agent-vs-skill" aria-label="Permalink to &quot;When should I use a command vs agent vs skill?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Concept</th><th>When to Use</th><th>Example</th></tr></thead><tbody><tr><td><strong>Agent</strong></td><td>Complex tasks requiring expertise, multi-step workflows, domain knowledge</td><td><code>@builder</code>, <code>@reviewer</code>, <code>@security</code></td></tr><tr><td><strong>Skill</strong></td><td>Focused, repeatable operations with a specific output format</td><td><code>/plan</code>, <code>/tdd</code>, <code>/audit</code>, <code>/discovery</code></td></tr><tr><td><strong>Vanilla prompt</strong></td><td>Simple, single-file tasks that don&#39;t need specialized knowledge</td><td>&quot;Fix the typo on line 42&quot;</td></tr></tbody></table><p><strong>Rule of thumb:</strong> If the task touches multiple files or needs verification steps, use an agent. If it&#39;s a repeatable process with a defined output, use a skill. If it&#39;s trivial, just ask directly.</p><h3 id="should-i-use-plan-mode-or-planner" tabindex="-1">Should I use plan mode or <code>@planner</code>? <a class="header-anchor" href="#should-i-use-plan-mode-or-planner" aria-label="Permalink to &quot;Should I use plan mode or \`@planner\`?&quot;">​</a></h3><p>Both work, but they serve different purposes:</p><ul><li><strong>Plan mode</strong> (built-in): Quick, lightweight planning inside your current conversation. Good for small features.</li><li><strong><code>@planner</code></strong>: Structured, phase-gated planning with acceptance criteria, cost estimates, and agent recommendations. Good for features that will involve multiple agents.</li></ul><p>For anything that will use <code>@orchestrator</code> or <code>@executor</code>, start with <code>@planner</code> — its output format is designed to feed directly into those agents.</p><h3 id="what-should-i-put-in-claude-md" tabindex="-1">What should I put in CLAUDE.md? <a class="header-anchor" href="#what-should-i-put-in-claude-md" aria-label="Permalink to &quot;What should I put in CLAUDE.md?&quot;">​</a></h3><p>Keep <code>CLAUDE.md</code> under 200 lines. Include:</p><ul><li>Project-specific conventions (naming, directory structure)</li><li>Key architectural decisions (&quot;we use React Query, not SWR&quot;)</li><li>Auto-dispatch rules (which agent for which intent)</li><li>Hard constraints (&quot;never use any in TypeScript&quot;)</li></ul><p>Don&#39;t include generic best practices, framework documentation, or rules that are already enforced by your linter/compiler. For detailed rules, use <code>.claude/rules/</code> files instead — they load on-demand.</p><h3 id="why-does-claude-sometimes-ignore-claude-md-instructions" tabindex="-1">Why does Claude sometimes ignore CLAUDE.md instructions? <a class="header-anchor" href="#why-does-claude-sometimes-ignore-claude-md-instructions" aria-label="Permalink to &quot;Why does Claude sometimes ignore CLAUDE.md instructions?&quot;">​</a></h3><p>Common causes:</p><ol><li><strong>Context overflow</strong> — The file is too long and gets truncated or deprioritized. Keep it under 200 lines.</li><li><strong>Conflicting instructions</strong> — Two rules contradict each other. Be explicit about priority.</li><li><strong>Vague language</strong> — &quot;Try to use...&quot; is weaker than &quot;MUST always use...&quot;. Use strong directives for hard rules.</li><li><strong>Context pollution</strong> — Long conversations dilute the impact of instructions. Use <code>/compact</code> at 50% context or start fresh sessions.</li></ol><h3 id="how-often-should-i-update-my-agents-and-claude-md" tabindex="-1">How often should I update my agents and CLAUDE.md? <a class="header-anchor" href="#how-often-should-i-update-my-agents-and-claude-md" aria-label="Permalink to &quot;How often should I update my agents and CLAUDE.md?&quot;">​</a></h3><p>Update when something changes in your project&#39;s conventions or when you notice agents repeatedly making the same mistakes. Don&#39;t update for every model improvement — Specialist Agent&#39;s agents are designed to work across model versions.</p><h3 id="can-i-convert-an-existing-codebase-into-specs-delete-it-and-regenerate" tabindex="-1">Can I convert an existing codebase into specs, delete it, and regenerate? <a class="header-anchor" href="#can-i-convert-an-existing-codebase-into-specs-delete-it-and-regenerate" aria-label="Permalink to &quot;Can I convert an existing codebase into specs, delete it, and regenerate?&quot;">​</a></h3><p>This is risky. Instead, use incremental approaches:</p><ol><li>Use <code>@scout</code> to analyze the existing codebase</li><li>Use <code>@analyst</code> to extract requirements from existing code</li><li>Use <code>@migrator</code> to modernize incrementally</li><li>Use <code>@refactor</code> for structural improvements</li></ol><p>Regenerating from scratch loses edge cases, bug fixes, and implicit knowledge baked into existing code.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="agents-are-not-following-my-architecture-md" tabindex="-1">Agents are not following my ARCHITECTURE.md <a class="header-anchor" href="#agents-are-not-following-my-architecture-md" aria-label="Permalink to &quot;Agents are not following my ARCHITECTURE.md&quot;">​</a></h3><ol><li>Verify the file is at <code>docs/ARCHITECTURE.md</code> (not the project root)</li><li>Check for syntax errors in the markdown</li><li>Run <code>/review-check-architecture</code> to validate</li><li>Ensure your rules are explicit - agents follow what&#39;s written literally</li></ol><h3 id="skills-return-command-not-found" tabindex="-1">Skills return &quot;command not found&quot; <a class="header-anchor" href="#skills-return-command-not-found" aria-label="Permalink to &quot;Skills return &quot;command not found&quot;&quot;">​</a></h3><p>Skills are not shell commands. They&#39;re instructions for Claude Code. Use them inside Claude Code&#39;s chat interface:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Correct - inside Claude Code</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/dev-create-component</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ProductCard</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Wrong - in a terminal</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> specialist-agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev-create-component</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ProductCard</span></span></code></pre></div><h3 id="generated-code-doesn-t-match-my-stack" tabindex="-1">Generated code doesn&#39;t match my stack <a class="header-anchor" href="#generated-code-doesn-t-match-my-stack" aria-label="Permalink to &quot;Generated code doesn&#39;t match my stack&quot;">​</a></h3><p>Your <code>ARCHITECTURE.md</code> may not reflect your actual stack. Common fixes:</p><ol><li>Update the API client section if you use Axios instead of fetch</li><li>Update the state management section if you use a different store library</li><li>Update the directory structure if your project uses a non-standard layout</li></ol><p>See <a href="/pr-preview/pr-65/customization/editing-patterns.html">Editing Patterns</a> for examples of common customizations.</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next?&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-65/guide/best-practices.html">Best Practices</a> - Tips for getting the most out of Specialist Agent</li><li><a href="/pr-preview/pr-65/guide/quick-start.html">Quick Start</a> - Get up and running</li><li><a href="/pr-preview/pr-65/guide/benchmark.html">Performance &amp; Cost</a> - Understand token usage</li><li><a href="/pr-preview/pr-65/reference/agents.html">All Agents</a> - Full reference catalog</li></ul>`,73)])])}const g=t(i,[["render",n]]);export{p as __pageData,g as default};
